CREATE OR REPLACE FUNCTION find_user_by_email(raw_email text)
RETURNS SETOF users AS $$
BEGIN
  RETURN QUERY EXECUTE 'SELECT * FROM users WHERE email = ''' || raw_email || '''';
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION find_user_by_email(raw_email text)
RETURNS SETOF users AS $$
BEGIN
  RETURN QUERY EXECUTE format('SELECT id, email FROM users WHERE email = %L', raw_email);
END;
$$ LANGUAGE plpgsql;
